import type { IFlexProps } from 'dt-react-component/flex';

const alignOptions = ['flex-start', 'center', 'flex-end'];
const justifyOptions = [
    'flex-start',
    'center',
    'flex-end',
    'space-between',
    'space-around',
    'space-evenly',
];

